350	// writeProjectVersions writes .ddx/versions.yaml with the current binary version.
351	// This file is system-managed and committed to git for version gating.
352	func writeProjectVersions(workingDir, ddxVersion string) {
353		if ddxVersion == "" || ddxVersion == "dev" {
354			ddxVersion = "dev"
355		}
356		versionsPath := filepath.Join(workingDir, ".ddx", "versions.yaml")
357		content := fmt.Sprintf("ddx_version: %q\n", ddxVersion)
358		if err := os.WriteFile(versionsPath, []byte(content), 0644); err != nil {
359			_, _ = fmt.Fprintf(os.Stderr, "Warning: could not write .ddx/versions.yaml: %v\n", err)
360		}
361	}
