363	// readProjectVersions reads ddx_version from .ddx/versions.yaml.
364	// Returns empty string if the file doesn't exist or can't be parsed.
365	func readProjectVersions(workingDir string) string {
366		versionsPath := filepath.Join(workingDir, ".ddx", "versions.yaml")
367		data, err := os.ReadFile(versionsPath)
368		if err != nil {
369			return ""
370		}
371		// Simple parse: look for ddx_version: "x.y.z" or ddx_version: x.y.z
372		for _, line := range strings.Split(string(data), "\n") {
373			line = strings.TrimSpace(line)
374			if strings.HasPrefix(line, "ddx_version:") {
375				val := strings.TrimPrefix(line, "ddx_version:")
376				val = strings.TrimSpace(val)
377				val = strings.Trim(val, `"'`)
378				return val
379			}
380		}
381		return ""
382	}
