	if err != nil {
		t.Fatalf("read beads.jsonl: %v", err)
	}
	if n := countLines(beads); n != 5 {
		t.Fatalf("standard profile: want 5 beads, got %d", n)
	}
}

// TestNewFixtureRepo_MultiProject verifies multi-project layout: the helper
